    const elemCount = {};
    for (const num of nums) {
        elemCount[num] = (elemCount[num] || 0) + 1;
    }
    let sum = 0;
    for (const [elem, count] of Object.entries(elemCount)) {
        if (count === 1) {
            sum += parseInt(elem);
