public int sumOfUniqueElements(int[] nums) {
    Map<Integer, Integer> elemCount = new HashMap<>();
    for (int num : nums) {
        elemCount.put(num, elemCount.getOrDefault(num, 0) + 1);
    }
    int sum = 0;
    for (Map.Entry<Integer, Integer> entry : elemCount.entrySet()) {
        if (entry.getValue() == 1) {
            sum += entry.getKey();
        }
    }
    return sum;
}
```


